import React, { useState, useEffect } from "react";
import axios from "axios";

export default function Categorias() {
  const [categorias, setCategorias] = useState([]);
  const [categoriaActual, setCategoriaActual] = useState({
    id: null,
    nombre: "",
  });
  const [showModal, setShowModal] = useState(false);
  const [modoEdicion, setModoEdicion] = useState(false);
  const [busqueda, setBusqueda] = useState("");

  useEffect(() => {
    obtenerCategorias();
  }, []);

  const obtenerCategorias = async () => {
    try {
      const res = await axios.get("http://localhost:5000/api/categorias");
      setCategorias(res.data);
    } catch (error) {
      console.error("❌ Error al obtener categorías:", error);
    }
  };

  const handleChange = (e) => {
    setCategoriaActual({ ...categoriaActual, [e.target.name]: e.target.value });
  };

  const abrirModalAgregar = () => {
    setCategoriaActual({ id: null, nombre: "" });
    setModoEdicion(false);
    setShowModal(true);
  };

  const abrirModalEditar = (categoria) => {
    setCategoriaActual(categoria);
    setModoEdicion(true);
    setShowModal(true);
  };

  const guardarCategoria = async (e) => {
    e.preventDefault();
    try {
      if (modoEdicion) {
        await axios.put(
          `http://localhost:5000/api/categorias/${categoriaActual.id}`,
          categoriaActual
        );
      } else {
        await axios.post("http://localhost:5000/api/categorias", categoriaActual);
      }
      setShowModal(false);
      obtenerCategorias();
    } catch (error) {
      console.error("❌ Error al guardar categoría:", error);
    }
  };

  const eliminarCategoria = async (id) => {
    if (window.confirm("¿Seguro que deseas eliminar esta categoría?")) {
      try {
        await axios.delete(`http://localhost:5000/api/categorias/${id}`);
        obtenerCategorias();
      } catch (error) {
        console.error("❌ Error al eliminar categoría:", error);
      }
    }
  };

  const categoriasFiltradas = categorias.filter((c) =>
    c.nombre?.toLowerCase().includes(busqueda.toLowerCase())
  );

  return (
    <div className="container mt-5">
      {/* Buscador y agregar */}
      <div className="d-flex justify-content-between align-items-center mb-4">
        <input
          type="text"
          placeholder="Buscar categoría..."
          className="form-control w-50"
          value={busqueda}
          onChange={(e) => setBusqueda(e.target.value)}
        />
        <button className="btn btn-success btn-lg" onClick={abrirModalAgregar}>
          ➕ Agregar Categoría
        </button>
      </div>

      {/* Cards de categorías */}
      <div className="row g-3">
        {categoriasFiltradas.map((c) => (
          <div key={c.id} className="col-md-3">
            <div className="card shadow-sm h-100">
              <div className="card-body d-flex flex-column justify-content-between">
                <h5 className="card-title">{c.nombre}</h5>
                <div className="mt-3 d-flex justify-content-between">
                  <button
                    className="btn btn-warning btn-sm"
                    onClick={() => abrirModalEditar(c)}
                  >
                    ✏️ Editar
                  </button>
                  <button
                    className="btn btn-danger btn-sm"
                    onClick={() => eliminarCategoria(c.id)}
                  >
                    🗑️ Eliminar
                  </button>
                </div>
              </div>
            </div>
          </div>
        ))}
        {categoriasFiltradas.length === 0 && (
          <div className="col-12 text-center text-muted">
            No hay categorías encontradas.
          </div>
        )}
      </div>

      {/* Modal */}
      {showModal && (
        <div
          className="modal fade show"
          style={{ display: "block", backgroundColor: "rgba(0,0,0,0.6)" }}
        >
          <div className="modal-dialog modal-dialog-centered">
            <div className="modal-content p-4 shadow-lg">
              <div className="modal-header">
                <h5 className="modal-title fw-bold">
                  {modoEdicion ? "Editar Categoría" : "Agregar Nueva Categoría"}
                </h5>
                <button
                  type="button"
                  className="btn-close"
                  onClick={() => setShowModal(false)}
                ></button>
              </div>
              <div className="modal-body">
                <form onSubmit={guardarCategoria}>
                  <div className="mb-3">
                    <label className="form-label">Nombre</label>
                    <input
                      type="text"
                      name="nombre"
                      value={categoriaActual.nombre}
                      onChange={handleChange}
                      className="form-control"
                      required
                    />
                  </div>
                  <div className="text-end">
                    <button
                      type="button"
                      className="btn btn-secondary me-2"
                      onClick={() => setShowModal(false)}
                    >
                      Cancelar
                    </button>
                    <button type="submit" className="btn btn-primary">
                      {modoEdicion ? "Guardar Cambios" : "Guardar Categoría"}
                    </button>
                  </div>
                </form>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
